import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export const LoginPage = () => {
  const [isSignup, setIsSignup] = useState(false);

  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('employee');
  const [department, setDepartment] = useState('');

  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const { login, signup } = useAuth(); // ✅ assumes signup added in context
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const cleanUsername = username.trim();
      const cleanPassword = password.trim();

      if (isSignup) {
        // ✅ SIGNUP FLOW
        await signup({
          username: cleanUsername,
          password: cleanPassword,
          role,
          departments: department ? [department] : []
        });

        // after signup → switch to login
        setIsSignup(false);
        setError("Account created successfully. Please login.");
      } else {
        // ✅ LOGIN FLOW
        const loggedInUser = await login(cleanUsername, cleanPassword);

        if (loggedInUser?.role === 'manager') {
          navigate('/mis');
        } else {
          navigate('/dashboard');
        }
      }

    } catch (err) {
      console.error("Auth error:", err);

      setError(
        err?.response?.data?.message ||
        err?.message ||
        (isSignup ? 'Signup failed' : 'Login failed')
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-600 to-blue-800 flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="bg-white rounded-lg shadow-2xl p-8">

          {/* Header */}
          <div className="text-center mb-6">
            <h1 className="text-3xl font-bold text-gray-800">
              {isSignup ? 'Create Account' : 'Task Dashboard'}
            </h1>
            <p className="text-gray-600 mt-1">
              {isSignup ? 'Sign up to continue' : 'Role-Based Task Management System'}
            </p>
          </div>

          {/* Error / Success */}
          {error && (
            <div className="mb-4 p-3 bg-red-100 border border-red-400 text-red-700 rounded">
              {error}
            </div>
          )}

          {/* Form */}
          <form onSubmit={handleSubmit}>

            {/* Username */}
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold mb-2">Username</label>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                disabled={loading}
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                required
              />
            </div>

            {/* Password */}
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold mb-2">Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                disabled={loading}
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                required
              />
            </div>

            {/* SIGNUP EXTRA FIELDS */}
            {isSignup && (
              <>
                {/* Role */}
                <div className="mb-4">
                  <label className="block text-gray-700 font-semibold mb-2">Role</label>
                  <select
                    value={role}
                    onChange={(e) => setRole(e.target.value)}
                    className="w-full px-4 py-2 border rounded-lg"
                  >
                    <option value="employee">Employee</option>
                    <option value="manager">Manager</option>
                  </select>
                </div>

                {/* Department */}
                <div className="mb-6">
                  <label className="block text-gray-700 font-semibold mb-2">Department</label>
                  <select
                    value={department}
                    onChange={(e) => setDepartment(e.target.value)}
                    className="w-full px-4 py-2 border rounded-lg"
                  >
                    <option value="">Select Department</option>
                    <option value="CRM">CRM</option>
                    <option value="Production">Production</option>
                    <option value="Sales">Sales</option>
                    <option value="Service">Service</option>
                  </select>
                </div>
              </>
            )}

            {/* Submit */}
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 text-white font-semibold py-2 rounded-lg hover:bg-blue-700 transition"
            >
              {loading
                ? (isSignup ? 'Creating...' : 'Logging in...')
                : (isSignup ? 'Sign Up' : 'Login')}
            </button>
          </form>

          {/* Toggle */}
          <div className="mt-6 text-center">
            <button
              onClick={() => {
                setIsSignup(!isSignup);
                setError('');
              }}
              className="text-blue-600 hover:underline"
            >
              {isSignup
                ? 'Already have an account? Login'
                : 'New user? Create account'}
            </button>
          </div>

        </div>
      </div>
    </div>
  );
};
